-- ---- CONSULTANT AGREEMENT ----------------------------------------------
INSERT INTO custom_pages_i18n (id, custom_page_id, locale, title, slug, content, summary, meta_title, meta_description) VALUES
  ('cpi-cagr-tr', 'cp-consultant-agreement', 'tr',
   'Danışman Sözleşmesi', 'danisman-sozlesmesi',
   '{"html":"<h2>GoldMoodAstro Danışman Sözleşmesi</h2><p><strong>Yürürlük tarihi:</strong> 2026-05-20</p><p>Bu sözleşme, GoldMoodAstro platformunda danışman olarak hizmet sunan kişi (\"Danışman\") ile platform sahibi GoldMoodAstro (\"Platform\") arasında akdedilir. Başvuru formunu onaylayarak aşağıdaki tüm maddeleri kabul etmiş sayılırsınız.</p><h3>1. Hizmet Tanımı</h3><p>Danışman; astroloji, doğum haritası, tarot, kahve falı, rüya tabiri ve onayladığı diğer uzmanlık alanlarında, platform üzerinden randevulu/sesli/görüntülü görüşmeler aracılığıyla danışanlara kişisel rehberlik hizmeti sunar. Hizmet tıbbi, hukuki ya da finansal tavsiye yerine geçmez.</p><h3>2. Komisyon ve Ödeme</h3><ul><li>Platform, danışmanın tamamladığı her seansın <strong>brüt tutarının %40’ını</strong> hizmet komisyonu olarak keser. Net hakediş = Brüt × (1 − 0,40) = Brüt × 0,60.</li><li>Komisyon oranı değiştiğinde danışmana en az 30 gün önceden e-posta ile bildirilir; değişikliği kabul etmeyen danışman sözleşmeyi feshedebilir.</li><li>Tamamlanmış seans hakedişleri <strong>7 günlük iade/uyuşmazlık (hold) süresi</strong> sonunda “kullanılabilir bakiye” durumuna geçer.</li><li>Danışman, kullanılabilir bakiyesinden <strong>ayda 1 kez ödeme talebi (takvim ayı)</strong> oluşturabilir. Talep platform tarafından incelenir, onaylanırsa <strong>3-5 iş günü</strong> içinde danışmanın IBAN’ına havale edilir.</li><li>Tek seferlik minimum çekim tutarı: <strong>100 TRY</strong>. Üst limit: 50.000 TRY.</li></ul><p>Komisyon oranı 2026-07-19 tarihinden itibaren %30’dan %40’a güncellenmiştir. Değişiklik tarihinde platformda hakedişi bulunan onaylı danışman olmadığından oran aynı gün yürürlüğe alınmıştır. Bu tarihten sonra yapılacak her oran değişikliği, aktif danışmanlara en az 30 gün önceden e-posta ile bildirilir.</p><h3>3. KYC ve Yasal Kimlik</h3><p>Para çekimi için <strong>kimlik doğrulama (KYC) zorunludur</strong>. Bireysel danışmanlar için TC kimlik numarası + kimlik fotoğrafı; şirket danışmanlar için vergi numarası, vergi dairesi, vergi levhası + imza sirküleri talep edilir. Platform belgelerin doğruluğunu kontrol eder, onay/red kararını e-posta ile bildirir.</p><h3>4. Vergi ve Fatura</h3><ul><li><strong>Şirket danışmanlar:</strong> Her hakediş için platforma e-fatura/e-arşiv kesmekle yükümlüdür. Aksi halde ödeme yapılmaz.</li><li><strong>Bireysel danışmanlar:</strong> Gelir vergisi beyanı ve stopaj yükümlülüğü danışmana aittir; platform vergi kesintisi yapmaz, yıllık beyanname danışmanın sorumluluğundadır.</li></ul><h3>5. Hesap Devri ve Hak Geri Alma</h3><p>Danışman hesabı devredilemez. Sahte kimlik, hizmet kalitesinde tekrarlanan şikayet, dolandırıcılık, KVKK ihlali ya da danışanla platform dışı para alışverişi durumunda platform hesabı askıya alma veya kapatma hakkını saklı tutar. Açık hakediş bakiyesi son talep + 30 gün içinde IBAN’a aktarılır.</p><h3>6. Kişisel Veri ve KVKK</h3><p>Danışman, danışan seans kayıtlarını, doğum verilerini ve kişisel bilgilerini yalnızca hizmet sunumu için kullanır; üçüncü kişilerle paylaşmaz; saklamaz. Platform 6698 sayılı KVKK kapsamında veri sorumlusudur; danışman veri işleyen sıfatıyla hareket eder.</p><h3>7. Sözleşmenin Süresi ve Fesih</h3><p>Sözleşme süresizdir. Her iki taraf da en az 14 gün önceden yazılı bildirimle sözleşmeyi feshedebilir. Fesih sonrası açık hakediş ödenmesi, randevu iadelerinin tamamlanması ve KYC belgelerinin saklı tutulması yükümlülüğü devam eder.</p><h3>8. Sorumluluk Sınırı</h3><p>Platform bir aracıdır; danışmanlık içeriğinin doğruluğundan, sonucundan veya danışan memnuniyetinden danışman sorumludur. Danışan zararından kaynaklanan dava ve talepler danışmana yöneltilir.</p><h3>9. Uyuşmazlık ve Yetkili Mahkeme</h3><p>İşbu sözleşmeden kaynaklanan uyuşmazlıklarda İstanbul (Anadolu) Mahkemeleri ve İcra Daireleri yetkilidir. Türkiye Cumhuriyeti hukuku uygulanır.</p><h3>10. Onay</h3><p>Başvuru formundaki “Sözleşmeyi okudum ve kabul ediyorum” kutusunu işaretleyerek bu sözleşmenin elektronik onayını vermiş sayılırsınız. Onay tarihi danışman profilinizde <em>agreement_accepted_at</em> alanında saklanır.</p>"}',
   'Danışman olarak GoldMoodAstro’da hizmet sunmanın koşullarını ve %40 komisyon dahil aylık ödeme akışını içeren sözleşme.',
   'Danışman Sözleşmesi — GoldMoodAstro',
   'GoldMoodAstro danışman sözleşmesi: komisyon, ödeme akışı, KYC, vergi ve fesih koşulları.'),

  ('cpi-cagr-en', 'cp-consultant-agreement', 'en',
   'Consultant Agreement', 'consultant-agreement',
   '{"html":"<h2>GoldMoodAstro Consultant Agreement</h2><p><strong>Effective date:</strong> 2026-05-20</p><p>This agreement is entered into between the consultant providing services on the GoldMoodAstro platform (\"Consultant\") and the platform owner GoldMoodAstro (\"Platform\"). By approving the application form you are deemed to have accepted all the clauses below.</p><h3>1. Service Definition</h3><p>The Consultant offers personal guidance to clients through scheduled audio/video sessions on the platform in approved areas of expertise (astrology, birth chart, tarot, coffee reading, dream interpretation, etc.). The service is not a substitute for medical, legal or financial advice.</p><h3>2. Commission & Payouts</h3><ul><li>The Platform deducts <strong>40%</strong> of the gross amount of every completed session as service commission. Net earnings = Gross × 0.60.</li><li>Any change in the commission rate is communicated to the Consultant at least 30 days in advance by e-mail; the Consultant who does not accept the change may terminate the agreement.</li><li>Completed-session earnings move to “available balance” after a <strong>7-day refund/dispute (hold) period</strong>.</li><li>The Consultant may create <strong>one payout request per calendar month</strong> from the available balance. Approved requests are transferred to the Consultant’s IBAN within <strong>3-5 business days</strong>.</li><li>Minimum single payout: <strong>100 TRY</strong>. Maximum: 50,000 TRY.</li></ul><p>The commission rate is updated from 30% to 40% effective 2026-07-19. As no approved consultant held any earnings on the platform at that date, the rate took effect the same day. Any future rate change will be notified to active consultants by e-mail at least 30 days in advance.</p><h3>3. KYC and Legal Identity</h3><p><strong>Identity verification (KYC) is mandatory</strong> for withdrawals. Individual consultants must provide a national ID number + ID photos; companies must provide a tax number, tax office, tax certificate + signature circular. The Platform verifies the documents and notifies its approval/rejection decision by e-mail.</p><h3>4. Taxes and Invoicing</h3><ul><li><strong>Company consultants</strong> must issue an e-invoice / e-archive document to the Platform for every payout. Otherwise no payment is made.</li><li><strong>Individual consultants</strong> are responsible for their own income-tax declaration and withholding; the Platform does not withhold tax, and the annual declaration is the Consultant’s responsibility.</li></ul><h3>5. Non-transferability and Termination</h3><p>The Consultant account is non-transferable. The Platform reserves the right to suspend or close the account in case of fake identity, repeated quality complaints, fraud, GDPR/KVKK violation or off-platform payment exchange with clients. Outstanding earnings are transferred to the IBAN within 30 days of the final payout request.</p><h3>6. Personal Data and Privacy</h3><p>The Consultant uses session recordings, birth data and personal information of clients solely for service delivery; never shares or stores them with third parties. The Platform is the data controller under the Turkish KVKK (Law 6698); the Consultant acts as data processor.</p><h3>7. Term and Termination</h3><p>The agreement is open-ended. Either party may terminate with at least 14 days’ prior written notice. Outstanding earnings, refund finalisation and document retention obligations survive termination.</p><h3>8. Limitation of Liability</h3><p>The Platform is an intermediary; the Consultant is liable for the accuracy, outcome and customer satisfaction of the consulting content. Customer-related claims are directed to the Consultant.</p><h3>9. Disputes and Jurisdiction</h3><p>Istanbul (Anatolian side) Courts and Enforcement Offices have jurisdiction over disputes arising from this agreement. Turkish law applies.</p><h3>10. Acknowledgement</h3><p>By ticking “I have read and accept the agreement” in the application form you are deemed to have given your electronic consent. The acceptance timestamp is stored in your consultant profile under <em>agreement_accepted_at</em>.</p>"}',
   'The agreement defining the terms of providing services as a consultant on GoldMoodAstro, including the 40% commission monthly payout flow.',
   'Consultant Agreement — GoldMoodAstro',
   'GoldMoodAstro consultant agreement: commission, payout flow, KYC, taxes and termination terms.'),

  ('cpi-cagr-de', 'cp-consultant-agreement', 'de',
   'Berater-Vereinbarung', 'berater-vereinbarung',
   '{"html":"<h2>GoldMoodAstro Berater-Vereinbarung</h2><p><strong>Inkrafttreten:</strong> 2026-05-20</p><p>Diese Vereinbarung wird zwischen der Beraterin/dem Berater (‚Berater/in‘) und der Plattform-Inhaberin GoldMoodAstro (‚Plattform‘) geschlossen. Mit der Bestätigung des Antragsformulars gilt jede der unten genannten Klauseln als angenommen.</p><h3>1. Dienstleistung</h3><p>Die Beraterin/der Berater bietet auf der Plattform in den genehmigten Fachgebieten (Astrologie, Geburtshoroskop, Tarot, Kaffeesatzlesen, Traumdeutung u. a.) terminierte Audio-/Video-Sitzungen als persönliche Lebensberatung an. Die Dienstleistung ersetzt keine medizinische, rechtliche oder finanzielle Beratung.</p><h3>2. Provision und Auszahlung</h3><ul><li>Die Plattform behält <strong>40 %</strong> des Bruttobetrags jeder abgeschlossenen Sitzung als Servicegebühr ein. Netto-Einkommen = Brutto × 0,60.</li><li>Eine Änderung der Provisionsrate wird mindestens 30 Tage im Voraus per E-Mail mitgeteilt; bei Nicht-Zustimmung kann gekündigt werden.</li><li>Einnahmen aus abgeschlossenen Sitzungen gehen nach <strong>7-tägiger Erstattungs-/Streit-Frist (Hold)</strong> in das ‚verfügbare Guthaben‘ über.</li><li>Aus dem verfügbaren Guthaben kann <strong>einmal pro Monat</strong> eine <strong>Auszahlungsanforderung</strong> erstellt werden. Genehmigte Anforderungen werden innerhalb von <strong>3-5 Werktagen</strong> auf die IBAN überwiesen.</li><li>Mindestauszahlung pro Vorgang: <strong>100 TRY</strong>. Höchstauszahlung: 50.000 TRY.</li></ul><p>Der Provisionssatz wird zum 19.07.2026 von 30 % auf 40 % aktualisiert. Da zu diesem Zeitpunkt kein zugelassener Berater Einkünfte auf der Plattform hatte, trat der Satz am selben Tag in Kraft. Jede künftige Satzänderung wird aktiven Beratern mindestens 30 Tage im Voraus per E-Mail mitgeteilt.</p><h3>3. KYC und Identität</h3><p>Für Auszahlungen ist die <strong>Identitätsprüfung (KYC) verpflichtend</strong>. Einzelpersonen liefern TC-Personalausweisnummer + Ausweisfoto; Unternehmen liefern Steuernummer, Finanzamt, Steuerbescheinigung + Unterschriftsregister. Die Plattform prüft die Dokumente und teilt die Entscheidung per E-Mail mit.</p><h3>4. Steuern und Rechnungsstellung</h3><ul><li><strong>Unternehmen</strong> stellen für jede Auszahlung eine E-Rechnung/E-Archiv aus. Andernfalls erfolgt keine Zahlung.</li><li><strong>Einzelpersonen</strong> sind für ihre eigene Einkommensteuererklärung und Quellensteuer verantwortlich; die Plattform behält keine Steuer ein.</li></ul><h3>5. Übertragbarkeit und Kündigung</h3><p>Berater-Konten sind nicht übertragbar. Bei gefälschter Identität, wiederholten Qualitätsbeschwerden, Betrug, KVKK-Verstoß oder Zahlungen außerhalb der Plattform kann das Konto gesperrt oder gelöscht werden. Offene Guthaben werden innerhalb von 30 Tagen nach dem letzten Auszahlungsantrag überwiesen.</p><h3>6. Personenbezogene Daten und Datenschutz</h3><p>Sitzungsdaten, Geburtsdaten und persönliche Informationen werden ausschließlich zur Leistungserbringung verwendet; sie werden nicht weitergegeben und nicht gespeichert. Die Plattform ist Verantwortliche nach KVKK 6698; die Beraterin/der Berater ist Auftragsverarbeiter.</p><h3>7. Laufzeit und Kündigung</h3><p>Die Vereinbarung läuft unbefristet. Jede Partei kann mit einer Frist von mindestens 14 Tagen schriftlich kündigen. Offene Guthaben, Erstattungsabschluss und Aufbewahrung von Unterlagen überdauern die Kündigung.</p><h3>8. Haftungsbegrenzung</h3><p>Die Plattform ist Vermittler; für Inhalt, Ergebnis und Zufriedenheit haftet ausschließlich die Beraterin/der Berater. Kundenseitige Ansprüche werden an sie/ihn weitergeleitet.</p><h3>9. Streitbeilegung</h3><p>Für Streitigkeiten aus dieser Vereinbarung sind die Gerichte und Vollstreckungsbehörden Istanbul (Anatolische Seite) zuständig. Es gilt türkisches Recht.</p><h3>10. Zustimmung</h3><p>Mit dem Anklicken von ‚Ich habe die Vereinbarung gelesen und akzeptiere sie‘ im Antragsformular gilt die elektronische Zustimmung als erteilt. Der Zeitstempel wird im Beraterprofil unter <em>agreement_accepted_at</em> gespeichert.</p>"}',
   'Die Vereinbarung über die Bedingungen für die Tätigkeit als Berater/in bei GoldMoodAstro, einschließlich des monatlichen Auszahlungsablaufs mit 40 % Provision.',
   'Berater-Vereinbarung — GoldMoodAstro',
   'GoldMoodAstro Berater-Vereinbarung: Provision, Auszahlungsablauf, KYC, Steuern und Kündigung.')
ON DUPLICATE KEY UPDATE
  title = VALUES(title),
  content = VALUES(content),
  meta_title = VALUES(meta_title),
  meta_description = VALUES(meta_description);

-- ---- PAYOUT FAQ ---------------------------------------------------------
INSERT INTO custom_pages_i18n (id, custom_page_id, locale, title, slug, content, summary, meta_title, meta_description) VALUES
  ('cpi-pofaq-tr', 'cp-payout-faq', 'tr',
   'Para Nasıl Hesabıma Geçer?', 'para-nasil-hesabima-gecer',
   '{"html":"<h2>Para Nasıl Hesabıma Geçer? — Danışman Tahsilat SSS</h2><p>Bu sayfa GoldMoodAstro’da bir seansın tamamlanmasından IBAN’ına havale gelene kadar olan akışı adım adım açıklar.</p><h3>1. Akışın Özeti</h3><ol><li><strong>Seans tamamlanır</strong> — danışan ödemesini yapmıştır, görüşme bitmiştir.</li><li><strong>Hakediş hesaplanır</strong> — net = brüt × (1 − %40 komisyon).</li><li><strong>7 günlük hold</strong> — hakediş “kullanılabilir” olmadan önce iade/şikayet süresi geçer.</li><li><strong>Kullanılabilir bakiye</strong> — bu süre sonunda cüzdanına yatar.</li><li><strong>Ödeme talebi oluştur (ayda 1 kez)</strong> — IBAN’ına havale için “Para Çek” butonuna tıkla. Takvim ayı içinde sadece 1 talep açılabilir.</li><li><strong>Admin inceler</strong> — talep onaylanır.</li><li><strong>3-5 iş günü</strong> — IBAN’ına havale ulaşır, durum “Ödendi” olur.</li></ol><h3>2. Komisyon</h3><p>Platform her tamamlanan seansın brüt tutarından <strong>%40 hizmet komisyonu</strong> keser. Örnek: 1.000 ₺’lik bir seans tamamlandığında cüzdanına 600 ₺ yansır. Komisyon oranı admin paneli üzerinden site_settings <em>platform_commission_rate</em> kaydından okunur. (Yürürlük: 2026-07-19.)</p><h3>3. Neden 7 Gün Bekleme (Hold)?</h3><p>Danışan yasal olarak seans sonrası ilk 7 gün içinde iade/itiraz hakkına sahiptir. Bu süre içinde uyuşmazlık doğmazsa hakediş otomatik olarak “kullanılabilir bakiye” olur. Süre admin paneli “wallet_hold_days” ayarından kontrol edilir.</p><h3>4. KYC Zorunlu mu?</h3><p>Evet. <strong>İlk para çekiminden önce</strong> kimlik doğrulama (KYC) tamamlanmış olmalıdır. Bireysel için TC kimlik no + kimlik fotoğrafı, şirket için vergi no + vergi levhası gerekir. Profilim → Hesap Tipi bölümünden KYC belgelerini yükleyip “KYC’yi Gönder” butonuna tıkla. Admin 1-3 iş günü içinde onay/red verir.</p><h3>5. Tek Seferde En Az / En Çok</h3><ul><li><strong>Minimum:</strong> 100 ₺</li><li><strong>Maksimum:</strong> 50.000 ₺ / tek talep</li><li>Bir talebi onayladıktan sonra bu tutar bakiyesinden düşülür ve “Ödeme bekleniyor” durumuna alınır.</li></ul><h3>6. Hangi IBAN’a Yatar?</h3><p>Her ödeme, talep oluşturulduğu andaki <strong>profilinde kayıtlı IBAN</strong>’a yapılır. IBAN’ını değiştirirsen sonraki talepler yeni IBAN’a gider; önceki talepler eski IBAN’da kalır.</p><h3>7. Vergi Faturası Lazım mı?</h3><ul><li><strong>Şirket hesabıysa:</strong> Her ödeme için platforma e-fatura/e-arşiv kesmen zorunludur. Belge gelmezse ödeme askıya alınır.</li><li><strong>Bireysel hesapsa:</strong> Yıllık gelir vergisi beyannamen sana aittir. Platform stopaj kesmez. Yıl sonunda toplam hakedişinin dökümünü admin panelinden indirebilirsin.</li></ul><h3>8. Reddedilirse Ne Olur?</h3><p>Eksik bilgi, IBAN-isim uyumsuzluğu veya KYC bekliyor gibi sebeplerle talep reddedilebilir. Reddedilen talep için tutar bakiyene geri yatırılır ve sana sebep mailiyle birlikte bildirim gelir. Düzelttikten sonra yeni talep oluşturabilirsin.</p><h3>9. Bildirimler</h3><p>Onaylandı / Ödendi / Reddedildi adımlarının her birinde sana e-posta + uygulama içi bildirim gönderilir.</p><h3>10. Sorularınız İçin</h3><p>Para akışıyla ilgili her türlü sorunu danışman destek panelinden açabilir veya <a href=\"mailto:destek@goldmoodastro.com\">destek@goldmoodastro.com</a> adresine yazabilirsin.</p>"}',
   'Tamamlanan seansın hakedişi nasıl hesaplanır, ne zaman çekilebilir, IBAN’ına ne zaman ulaşır — adım adım.',
   'Para Nasıl Hesabıma Geçer — GoldMoodAstro',
   'GoldMoodAstro danışman tahsilat süreci: %40 komisyon, 7 gün hold, KYC, aylık ödeme talebi ve 3-5 iş günü transfer SSS.'),

  ('cpi-pofaq-en', 'cp-payout-faq', 'en',
   'How Do I Get Paid?', 'how-do-i-get-paid',
   '{"html":"<h2>How Do I Get Paid? — Consultant Payout FAQ</h2><p>This page explains the full flow from completing a session on GoldMoodAstro to receiving the payment in your IBAN.</p><h3>1. Flow Summary</h3><ol><li><strong>Session completed</strong> — client has paid, call ended.</li><li><strong>Earnings calculated</strong> — net = gross × (1 − 40% commission).</li><li><strong>7-day hold</strong> — refund/dispute window before earnings become “available”.</li><li><strong>Available balance</strong> — moves into your wallet.</li><li><strong>Create payout request (once per calendar month)</strong> — click “Withdraw” to request transfer to your IBAN. Only one request can be opened per calendar month.</li><li><strong>Admin reviews</strong> — request is approved.</li><li><strong>3-5 business days</strong> — bank transfer arrives, status becomes “Paid”.</li></ol><h3>2. Commission</h3><p>The platform deducts a <strong>40% service commission</strong> from every completed session’s gross amount. Example: a 1,000 ₺ session adds 600 ₺ to your wallet. The rate is read from the admin <em>platform_commission_rate</em> setting. (Effective 2026-07-19.)</p><h3>3. Why a 7-day hold?</h3><p>Clients legally have a 7-day refund/dispute window after a session. If no dispute occurs in that window, earnings automatically become “available balance”. The window is controlled by the admin “wallet_hold_days” setting.</p><h3>4. Is KYC mandatory?</h3><p>Yes. <strong>Before your first withdrawal</strong>, identity verification (KYC) must be completed. Individuals upload national ID + ID photos; companies upload tax number + tax certificate. Go to Profile → Account Type, upload documents and click “Submit KYC”. Admin approves/rejects within 1-3 business days.</p><h3>5. Limits per Request</h3><ul><li><strong>Minimum:</strong> 100 ₺</li><li><strong>Maximum:</strong> 50,000 ₺ / single request</li><li>Once a request is created the amount is moved from your balance to “pending withdrawal”.</li></ul><h3>6. Which IBAN Receives the Payout?</h3><p>Each payment goes to the IBAN <strong>currently saved on your profile</strong> when the request is created. If you change the IBAN later, only future requests go to the new account.</p><h3>7. Do I Need to Invoice?</h3><ul><li><strong>Company accounts</strong> must issue an e-invoice/e-archive document for every payout. Otherwise payment is suspended.</li><li><strong>Individuals</strong> are responsible for their own annual income-tax declaration. Platform does not withhold tax. You can download a full earnings statement from the admin panel at year-end.</li></ul><h3>8. What If a Request Is Rejected?</h3><p>Requests may be rejected for missing info, IBAN-name mismatch or pending KYC. The amount is returned to your wallet and you receive an e-mail with the reason. Fix the issue and create a new request.</p><h3>9. Notifications</h3><p>You receive an e-mail + in-app notification at every step: Approved / Paid / Rejected.</p><h3>10. Need Help?</h3><p>For any question about the payout flow, open a ticket from the consultant support panel or write to <a href=\"mailto:destek@goldmoodastro.com\">destek@goldmoodastro.com</a>.</p>"}',
   'Step by step: how a completed session’s earnings are calculated, when they become available, and when the transfer reaches your IBAN.',
   'How Do I Get Paid — GoldMoodAstro',
   'GoldMoodAstro consultant payout FAQ: 40% commission, 7-day hold, KYC, monthly withdrawal request and 3-5 business day transfer.'),

  ('cpi-pofaq-de', 'cp-payout-faq', 'de',
   'Wie erhalte ich mein Geld?', 'wie-erhalte-ich-mein-geld',
   '{"html":"<h2>Wie erhalte ich mein Geld? — Berater-Auszahlungs-FAQ</h2><p>Diese Seite erklärt den vollständigen Ablauf vom Abschluss einer Sitzung bei GoldMoodAstro bis zur Ankunft des Geldes auf deiner IBAN.</p><h3>1. Ablauf</h3><ol><li><strong>Sitzung abgeschlossen</strong> — Kundin/Kunde hat gezahlt, Gespräch beendet.</li><li><strong>Einkommen berechnet</strong> — Netto = Brutto × (1 − 40 % Provision).</li><li><strong>7-tägige Sperrfrist</strong> — Erstattungs-/Streit-Fenster, bevor Einkommen verfügbar wird.</li><li><strong>Verfügbares Guthaben</strong> — geht in deine Wallet.</li><li><strong>Auszahlungsanforderung (einmal pro Monat)</strong> — “Auszahlen” klicken, um die Überweisung anzufordern. Pro Kalendermonat ist nur eine Anforderung möglich.</li><li><strong>Admin prüft</strong> — Anforderung wird genehmigt.</li><li><strong>3-5 Werktage</strong> — Überweisung kommt auf der IBAN an, Status wird “Bezahlt”.</li></ol><h3>2. Provision</h3><p>Die Plattform behält <strong>40 % Servicegebühr</strong> vom Bruttobetrag jeder Sitzung ein. Beispiel: Eine 1.000 ₺ Sitzung bringt 600 ₺ ins Wallet. Der Satz wird aus der Admin-Einstellung <em>platform_commission_rate</em> gelesen. (Stichtag 19.07.2026.)</p><h3>3. Warum 7 Tage Sperrfrist?</h3><p>Kundinnen und Kunden haben ein 7-Tage-Erstattungsrecht. Ohne Streit in dieser Zeit wird das Einkommen automatisch ‚verfügbar‘. Steuerbar über “wallet_hold_days”.</p><h3>4. Ist KYC Pflicht?</h3><p>Ja. Vor der ersten Auszahlung muss die Identitätsprüfung abgeschlossen sein. Einzelpersonen: TC-Personalausweis + Foto. Unternehmen: Steuernummer + Steuerbescheinigung. Im Profil → “Kontotyp” Dokumente hochladen und “KYC einreichen” klicken. Admin entscheidet in 1-3 Werktagen.</p><h3>5. Limits pro Anforderung</h3><ul><li><strong>Min.:</strong> 100 ₺</li><li><strong>Max.:</strong> 50.000 ₺ / Anforderung</li></ul><h3>6. Auf welche IBAN?</h3><p>Jede Zahlung geht auf die IBAN, die <strong>bei Erstellung der Anforderung</strong> im Profil hinterlegt ist.</p><h3>7. Brauche ich eine Rechnung?</h3><ul><li><strong>Unternehmen:</strong> für jede Auszahlung eine E-Rechnung/E-Archiv ausstellen.</li><li><strong>Einzelpersonen:</strong> Jährliche Einkommensteuererklärung in Eigenverantwortung.</li></ul><h3>8. Ablehnung</h3><p>Bei Ablehnung wird der Betrag in die Wallet zurückgebucht; Grund wird per E-Mail mitgeteilt. Korrigieren und neu anfordern.</p><h3>9. Benachrichtigungen</h3><p>E-Mail + In-App-Hinweis bei jedem Schritt: Genehmigt / Bezahlt / Abgelehnt.</p><h3>10. Hilfe</h3><p>Fragen zum Auszahlungsablauf: Ticket im Beratersupport oder Mail an <a href=\"mailto:destek@goldmoodastro.com\">destek@goldmoodastro.com</a>.</p>"}',
   'Schritt für Schritt: wie Einkommen berechnet wird, wann es verfügbar wird und wann die Überweisung auf der IBAN ankommt.',
   'Wie erhalte ich mein Geld — GoldMoodAstro',
   'GoldMoodAstro Berater-Auszahlungs-FAQ: 40 % Provision, 7 Tage Sperrfrist, KYC, monatliche Auszahlungsanforderung und 3-5 Werktage Überweisung.')
ON DUPLICATE KEY UPDATE
  title = VALUES(title),
